      { name: "按量付费", price: "按使用量计费", features: ["Search请求约$0.01-0.025/次", "Get Contents约$0.01/次", "无月度最低消费限制", "超出免费额度后自动计费", "支持信用卡在线充值"] },
      { name: "企业套餐", price: "联系销售定制", features: ["定制化高并发请求配额", "专属SLA服务协议保障", "优先技术支持响应", "定制化索引和过滤需求", "发票和合规文件支持"] }
