      { name: "API 按量计费", price: "按 token 用量付费", features: ["DeepSeek-V3 输入约 ¥1/百万 token", "DeepSeek-V3 输出约 ¥2/百万 token", "DeepSeek-R1 推理模型独立定价", "新用户赠送免费 API 额度", "与 OpenAI SDK 接口兼容"] },
      { name: "开源本地部署", price: "免费（自备算力）", features: ["HuggingFace 完整模型权重下载", "支持 Ollama / vLLM 本地运行", "数据完全不出本地网络", "支持垂直领域微调定制", "商业使用友好的开源协议"] }
