      { name: "Plus + AI", price: "$22/月（含AI，年付约$18/月）", features: ["无限块内容与文件上传", "无限访客协作权限", "完整 Notion AI 功能无限使用", "30天页面版本历史", "自定义域名与高级权限管理"] },
      { name: "Business + AI", price: "$28/月/人（含AI，年付约$22/月）", features: ["所有 Plus 功能", "SAML SSO 单点登录", "90天页面版本历史", "高级分析与工作区洞察", "批量PDF导出与优先客服支持"] }
