      { name: "Silver", price: "$45/月", features: ["每月50次内容查询分析", "更高AI写作字数额度", "最多5个内容项目", "团队协作功能（2人）", "内容评分历史追踪"] },
      { name: "Gold", price: "$69/月", features: ["每月75次内容查询分析", "无限AI写作字数额度", "最多10个内容项目", "团队协作功能（4人）", "优先客户支持响应"] }
